import{_ as r,c as i,o as t,a5 as l,j as a}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.7：交互式问答 + 移动端优化","description":"","frontmatter":{},"headers":[],"relativePath":"changelog/v1.1.7.md","filePath":"changelog/v1.1.7.md","lastUpdated":1772014034000}'),h={name:"changelog/v1.1.7.md"};function n(d,e,o,s,c,p){return t(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="v1-1-7-交互式问答-移动端优化" tabindex="-1">v1.1.7：交互式问答 + 移动端优化 <a class="header-anchor" href="#v1-1-7-交互式问答-移动端优化" aria-label="Permalink to “v1.1.7：交互式问答 + 移动端优化”">​</a></h1><p><strong>发布日期</strong>：2026年1月8日</p><hr><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to “一句话总结”">​</a></h2><p>这次更新新增了<strong>交互式问答工具</strong>，让 AI 可以主动向你提问收集信息，同时优化了窄屏/移动端体验。</p><hr><h2 id="新功能-交互式问答工具" tabindex="-1">新功能：交互式问答工具 <a class="header-anchor" href="#新功能-交互式问答工具" aria-label="Permalink to “新功能：交互式问答工具”">​</a></h2><h3 id="这次更新了什么" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>AI 现在可以<strong>主动向你提问</strong>，收集你的偏好和需求，而不是猜测你想要什么。</p><h3 id="使用场景" tabindex="-1">使用场景 <a class="header-anchor" href="#使用场景" aria-label="Permalink to “使用场景”">​</a></h3><p>比如你说「帮我创建一个项目」，AI 可能会问：</p><ul><li>使用什么框架？（React / Vue / Svelte）</li><li>需要 TypeScript 吗？（是 / 否）</li><li>要配置哪些工具？（ESLint / Prettier / 测试框架）</li></ul><p>你选择后，AI 再按你的选择执行，避免做出不符合预期的决定。</p><h3 id="为什么有用" tabindex="-1">为什么有用？ <a class="header-anchor" href="#为什么有用" aria-label="Permalink to “为什么有用？”">​</a></h3><p>之前 AI 遇到不确定的情况，要么猜测（可能猜错），要么停下来用文字问你（不方便选择）。现在有了结构化的问答界面，交互更清晰。</p><hr><h2 id="改进-窄屏-移动端体验" tabindex="-1">改进：窄屏/移动端体验 <a class="header-anchor" href="#改进-窄屏-移动端体验" aria-label="Permalink to “改进：窄屏/移动端体验”">​</a></h2><h3 id="这次更新了什么-1" tabindex="-1">这次更新了什么？ <a class="header-anchor" href="#这次更新了什么-1" aria-label="Permalink to “这次更新了什么？”">​</a></h3><p>在窄屏幕（手机、小窗口）下：</p><ul><li>侧边栏改为<strong>覆盖式弹出</strong>，不再挤压主内容</li><li>自动隐藏顶部和底部栏，留出更多空间</li><li>自动补全高度自适应屏幕</li></ul><h3 id="效果" tabindex="-1">效果 <a class="header-anchor" href="#效果" aria-label="Permalink to “效果”">​</a></h3><p>在手机或小窗口使用 OpenCode 更舒服了。</p><hr><h2 id="改进-长命令输出可折叠" tabindex="-1">改进：长命令输出可折叠 <a class="header-anchor" href="#改进-长命令输出可折叠" aria-label="Permalink to “改进：长命令输出可折叠”">​</a></h2><h3 id="之前的问题" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题" aria-label="Permalink to “之前的问题”">​</a></h3><p>执行一个输出很长的命令（比如 <code>npm install</code>），整个输出会占满屏幕，很难看到其他内容。</p><h3 id="现在的情况" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况" aria-label="Permalink to “现在的情况”">​</a></h3><p>长命令输出现在<strong>默认折叠</strong>，点击可展开查看完整内容。</p><hr><h2 id="改进-配置优先级修复" tabindex="-1">改进：配置优先级修复 <a class="header-anchor" href="#改进-配置优先级修复" aria-label="Permalink to “改进：配置优先级修复”">​</a></h2><h3 id="之前的问题-1" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-1" aria-label="Permalink to “之前的问题”">​</a></h3><p>本地项目配置（<code>.opencode/settings.json</code>）有时候无法覆盖全局配置。</p><h3 id="现在的情况-1" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-1" aria-label="Permalink to “现在的情况”">​</a></h3><p>配置优先级现在正确工作：<strong>项目配置 &gt; 全局配置 &gt; 远程配置</strong>。</p><hr><h2 id="桌面版-外部链接在浏览器打开" tabindex="-1">桌面版：外部链接在浏览器打开 <a class="header-anchor" href="#桌面版-外部链接在浏览器打开" aria-label="Permalink to “桌面版：外部链接在浏览器打开”">​</a></h2><h3 id="之前的问题-2" tabindex="-1">之前的问题 <a class="header-anchor" href="#之前的问题-2" aria-label="Permalink to “之前的问题”">​</a></h3><p>点击对话中的链接，会在桌面应用内打开，体验不好。</p><h3 id="现在的情况-2" tabindex="-1">现在的情况 <a class="header-anchor" href="#现在的情况-2" aria-label="Permalink to “现在的情况”">​</a></h3><p>外部链接现在会在<strong>默认浏览器</strong>中打开。</p><hr><h2 id="要不要升级" tabindex="-1">要不要升级？ <a class="header-anchor" href="#要不要升级" aria-label="Permalink to “要不要升级？”">​</a></h2><table tabindex="0"><thead><tr><th>情况</th><th>建议</th></tr></thead><tbody><tr><td>经常在手机/小屏幕使用</td><td>✅ 升级</td></tr><tr><td>希望 AI 更智能地提问</td><td>✅ 升级</td></tr><tr><td>配置覆盖不生效</td><td>✅ 升级</td></tr><tr><td>用得好好的</td><td>可以等下次</td></tr></tbody></table><p><strong>升级命令</strong>：</p>',44),a("div",{class:"language-bash"},[a("button",{title:"Copy Code",class:"copy"}),a("span",{class:"lang"},"bash"),a("pre",null,[a("code",{"v-pre":""},"opencode upgrade")])],-1),l('<hr><h2 id="技术细节-可跳过" tabindex="-1">技术细节（可跳过） <a class="header-anchor" href="#技术细节-可跳过" aria-label="Permalink to “技术细节（可跳过）”">​</a></h2><details><summary>点击展开完整更新列表</summary><h3 id="core-核心" tabindex="-1">Core（核心） <a class="header-anchor" href="#core-核心" aria-label="Permalink to “Core（核心）”">​</a></h3><ul><li>添加交互式问答工具，用于收集用户偏好和澄清指令</li><li>ACP tool_call_update 事件添加 kind、title、rawInput 字段（@noamzbr）</li><li>debug 命令添加帮助文本（@assagman）</li><li>允许禁用 .claude 提示词和 skills 加载（@freespace8）</li><li>修复生成标题时 transform 选项冲突问题</li><li>长工具输出写入文件</li><li>简化 Task 工具子代理过滤逻辑（@malhashemi）</li><li>改进标题生成，避免重复的「Analyzing...」前缀</li><li>修复 MCP OAuth 发现时使用正确的授权服务器 URL（@rscarvalho）</li><li>配置优先级修复，本地配置正确覆盖远程配置（@elithrar）</li><li>更新 Homebrew formula</li></ul><h3 id="tui-终端界面" tabindex="-1">TUI（终端界面） <a class="header-anchor" href="#tui-终端界面" aria-label="Permalink to “TUI（终端界面）”">​</a></h3><ul><li>恢复权限重构中移除的 showDetails 检查（@ryanwyler）</li><li>致命错误退出时正确恢复终端状态（@itsrainingmani）</li><li>侧边栏可见时隐藏顶部和底部栏，优化响应式布局</li><li>简化会话设置管理（@maxstevens-nl）</li><li>窄屏幕使用覆盖式侧边栏</li><li>长命令输出可折叠展开</li><li>移除用户名显示开关，简化用户消息元数据</li><li>改进问答选项的缩进和标签清晰度</li><li>分叉对话时正确插入消息文本到输入框（@ariane-emory）</li><li>权限选择文本使用选中前景色（@ariane-emory）</li><li>自动补全高度限制在可用屏幕空间内（@Raviguntakala）</li><li>橙色主题添加 selectedListItemText 提升按钮文字可见性（@ThanhNguyxn）</li></ul><h3 id="desktop-桌面版" tabindex="-1">Desktop（桌面版） <a class="header-anchor" href="#desktop-桌面版" aria-label="Permalink to “Desktop（桌面版）”">​</a></h3><ul><li>显示没有有效 release_date 的自定义模型（@zerone0x）</li><li>外部链接在默认浏览器打开（@athal7）</li></ul><h3 id="社区贡献" tabindex="-1">社区贡献 <a class="header-anchor" href="#社区贡献" aria-label="Permalink to “社区贡献”">​</a></h3><p>感谢 15 位社区贡献者！</p></details><hr><p><a href="./">← 返回更新日志</a></p>',5)])])}const _=r(h,[["render",n]]);export{m as __pageData,_ as default};
